// annotate.js
import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

import AnnotationTopBar from '../components/AnnotationTopBar';
import AnnotationCanvas from '../components/AnnotationCanvas';
import AnnotationListSidebar from '../components/AnnotationListSidebar';
import './Annotate.css';

// 1) NEW IMPORT FOR POLYGON CLIPPING
// You can choose either "martinez-polygon-clipping" or "polygon-clipping" library.
// This example uses "martinez-polygon-clipping".
//import martinez from 'martinez-polygon-clipping';
import polygonClipping from 'polygon-clipping';

export default function Annotate() {
  const navigate = useNavigate();
  const { state } = useLocation();
  const folderInfo = state?.folderInfo;

  if (!folderInfo) {
    return (
      <div style={{ padding: 20 }}>
        <h2>No folder info found. Please create a task first.</h2>
        <button onClick={() => navigate('/')}>Go Home</button>
      </div>
    );
  }

  const { folderId, taskName, labelClasses, files } = folderInfo;

  // -------------- Annotations for each image --------------
  const [annotations, setAnnotations] = useState({});
  const [undoStack, setUndoStack] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  // Tools: move, bbox, polygon, polyline, point, ellipse, segmentation
  const [selectedTool, setSelectedTool] = useState('move');
  // For “segmentation” specifically, we have a small dropdown (Instance, Semantic, Panoptic)
  const [segmentationType, setSegmentationType] = useState('instance');

  const [selectedLabelClass, setSelectedLabelClass] = useState(
    labelClasses[0]?.name || ''
  );
  const [scale, setScale] = useState(1.0);

  const currentFileUrl = files[currentIndex]?.url;
  const currentShapes = annotations[currentFileUrl] || [];

  // Whenever shapes change, store old state in undoStack
  const handleAnnotationsChange = (newShapes) => {
    const updated = {
      ...annotations,
      [currentFileUrl]: newShapes,
    };
    setUndoStack([...undoStack, annotations]);
    setRedoStack([]);
    setAnnotations(updated);
  };

  // -------------- Undo / Redo --------------
  const undo = () => {
    if (undoStack.length === 0) return;
    const prev = undoStack[undoStack.length - 1];
    setRedoStack([...redoStack, annotations]);
    setUndoStack(undoStack.slice(0, -1));
    setAnnotations(prev);
  };

  const redo = () => {
    if (redoStack.length === 0) return;
    const next = redoStack[redoStack.length - 1];
    setUndoStack([...undoStack, annotations]);
    setRedoStack(redoStack.slice(0, -1));
    setAnnotations(next);
  };

  // -------------- Deletion & Update --------------
  const handleDeleteAnnotation = (index) => {
    const arr = [...currentShapes];
    arr.splice(index, 1);
    handleAnnotationsChange(arr);
  };

  const handleUpdateAnnotation = (index, changes) => {
    const arr = [...currentShapes];
    arr[index] = { ...arr[index], ...changes };
    handleAnnotationsChange(arr);
  };

  // -------------- Navigation --------------
  const handlePrev = () => {
    if (currentIndex > 0) setCurrentIndex((i) => i - 1);
  };
  const handleNext = () => {
    if (currentIndex < files.length - 1) setCurrentIndex((i) => i + 1);
  };

  // -------------- Zoom --------------
  const handleZoomIn = () => setScale((s) => Math.min(s + 0.1, 5));
  const handleZoomOut = () => setScale((s) => Math.max(s - 0.1, 0.2));
  const handleWheelZoom = (deltaY) => {
    if (deltaY < 0) handleZoomIn();
    else handleZoomOut();
  };

  // -------------- Save --------------
  const handleSave = async () => {
    const bodyData = {
      folderId,
      taskName,
      labelClasses,
      annotations,
    };
    try {
      const res = await fetch('http://localhost:4000/api/annotations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bodyData),
      });
      const data = await res.json();
      alert('Saved: ' + data.message);
    } catch (err) {
      console.error(err);
      alert('Error saving');
    }
  };

  // -------------- Keyboard Shortcuts --------------
  useEffect(() => {
    const handleKey = (e) => {
      const key = e.key;

      // Tools
      if (key === 'm' || key === 'M') {
        setSelectedTool('move');
      } else if (key === 'b' || key === 'B') {
        setSelectedTool('bbox');
      } else if (key === 'p' || key === 'P') {
        setSelectedTool('polygon');
      } else if (key === 'l' || key === 'L') {
        setSelectedTool('polyline');
      } else if (key === 'o' || key === 'O') {
        setSelectedTool('point');
      } else if (key === 'e' || key === 'E') {
        setSelectedTool('ellipse');
      }
      // Segmentation on plain "S"
      else if ((key === 's' || key === 'S') && e.ctrlKey) {
        // Ctrl+S => Save
        e.preventDefault();
        handleSave();
      } else if (key === 's' || key === 'S') {
        // Just S => Segmentation
        setSelectedTool('segmentation');
      }

      // Esc => cancel shape
      if (key === 'Escape') {
        const event = new CustomEvent('cancel-annotation');
        window.dispatchEvent(event);
      }
      // Next / Prev
      if (key === 'ArrowRight') {
        handleNext();
      } else if (key === 'ArrowLeft') {
        handlePrev();
      }

      // Undo / Redo
      if (e.ctrlKey && (key === 'z' || key === 'Z')) {
        e.preventDefault();
        undo();
      } else if (e.ctrlKey && (key === 'y' || key === 'Y')) {
        e.preventDefault();
        redo();
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
    // eslint-disable-next-line
  }, [annotations, undoStack, redoStack]);

  // -------------- Export Logic --------------
  const [exportOpen, setExportOpen] = useState(false);
  const openExport = () => setExportOpen(true);
  const closeExport = () => setExportOpen(false);

  const exportAnnotations = (format) => {
    if (format === 'coco') {
      downloadCOCO();
    } else if (format === 'yolo') {
      downloadYOLO();
    } else if (format === 'pascal') {
      downloadPascal();
    }
    closeExport();
  };

  function downloadFile(url, filename) {
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }

  function downloadCOCO() {
    alert('COCO export not yet implemented!');
  }
  function downloadYOLO() {
    alert('YOLO export not yet implemented!');
  }
  function downloadPascal() {
    alert('Pascal VOC export not yet implemented!');
  }

  // -------------- When annotation finishes => switch to move --------------
  const handleFinishShape = () => {
    setSelectedTool('move');
  };

  /////////////////////////////////////////////////////////////////////////
  //  NEW CODE BELOW: FILL BACKGROUND LOGIC FOR SEMANTIC / PANOPTIC ONLY  //
  /////////////////////////////////////////////////////////////////////////

  /**
   * Helper to find a color that isn't used yet.
   * We default to BLACK (#000000), but if any label already uses black,
   * pick another color (#333333, for example).
   */
  function getBackgroundColor() {
    const usedColors = labelClasses.map((lc) => lc.color?.toLowerCase());
    const black = '#000000';
    if (!usedColors.includes(black)) {
      return black;
    }
    // fallback to some dark color
    let fallback = '#333333';
    // keep searching if that is also used
    while (usedColors.includes(fallback)) {
      // just lighten or darken it further
      fallback = fallback === '#333333' ? '#222222' : '#444444';
    }
    return fallback;
  }

  /**
   * Convert any existing annotation to a polygon-for-union using the image coordinate system:
   * - BBox => 4-corner polygon
   * - Polygon => itself
   * - Polyline => approximate by slight buffer or just skip if you'd prefer
   * - Ellipse => approximate bounding box or polygon sampling
   * - Point => approximate small bounding box or skip
   * - "points" => same approach
   * This function returns an array-of-polygons in the "martinez" format:
   *     [ [ [x0, y0], [x1, y1], ..., [x0, y0] ] ]  // ring-based polygons
   * Because we do union/difference with them.
   */
  function annotationToPolygons(ann) {
    if (ann.type === 'bbox') {
      const { x, y, width, height } = ann;
      const x2 = x + width;
      const y2 = y + height;
      // A single polygon ring: [ [ x,y ], [ x2,y ], [ x2,y2 ], [ x,y2 ], [ x,y ] ]
      return [
        [
          [x, y],
          [x2, y],
          [x2, y2],
          [x, y2],
          [x, y],
        ],
      ];
    } else if (ann.type === 'polygon') {
      // Points: [ {x, y}, {x, y}, ... ]
      const ring = ann.points.map((p) => [p.x, p.y]);
      // Close the ring if not already
      if (
        ring.length > 0 &&
        (ring[0][0] !== ring[ring.length - 1][0] ||
          ring[0][1] !== ring[ring.length - 1][1])
      ) {
        ring.push(ring[0]);
      }
      return [ring];
    } else if (ann.type === 'polyline') {
      // This is trickier to do a true difference with holes.
      // For simplicity, turn it into a polygon by a small buffer (or skip).
      // Here, let's just skip or treat it as a line bounding box for demonstration.
      const xs = ann.points.map((p) => p.x);
      const ys = ann.points.map((p) => p.y);
      const minX = Math.min(...xs);
      const maxX = Math.max(...xs);
      const minY = Math.min(...ys);
      const maxY = Math.max(...ys);
      return [
        [
          [minX, minY],
          [maxX, minY],
          [maxX, maxY],
          [minX, maxY],
          [minX, minY],
        ],
      ];
    } else if (ann.type === 'ellipse') {
      // Approximate ellipse by bounding box for simplicity
      const { x, y, radiusX, radiusY } = ann;
      const x1 = x - radiusX;
      const y1 = y - radiusY;
      const x2 = x + radiusX;
      const y2 = y + radiusY;
      return [
        [
          [x1, y1],
          [x2, y1],
          [x2, y2],
          [x1, y2],
          [x1, y1],
        ],
      ];
    } else if (ann.type === 'point') {
      // A point is basically zero area. Let's ignore or treat as a small box.
      const { x, y } = ann;
      return [
        [
          [x - 1, y - 1],
          [x + 1, y - 1],
          [x + 1, y + 1],
          [x - 1, y + 1],
          [x - 1, y - 1],
        ],
      ];
    } else if (ann.type === 'points') {
      // A set of points => union of small boxes
      // We'll just union them, or you might skip. For demo, do them individually:
      const polygons = ann.points.map((pt) => {
        return [
          [
            [pt.x - 1, pt.y - 1],
            [pt.x + 1, pt.y - 1],
            [pt.x + 1, pt.y + 1],
            [pt.x - 1, pt.y + 1],
            [pt.x - 1, pt.y - 1],
          ],
        ];
      });
      // Return an array of polygon rings. We'll reduce them together in union step.
      // For now, just return them. Our union code can handle multiple shapes.
      return polygons;
    }
    return [];
  }

  /**
   * Convert the entire image (0,0) -> (w,h) into a polygon ring for “background.”
   * We assume you can figure out the actual image width/height from the loaded image.
   * Because we only store the URL and shapes, we rely on the <AnnotationCanvas> giving us
   * image dimensions or a global reference. 
   * 
   * For demonstration, we'll pass them in from <AnnotationCanvas> or store them in state, 
   * but here we do a simpler approach: we’ll get the width/height from the first bounding box 
   * if it exists or from a known place. You might need a more robust approach in practice!
   */
  const [imageDims, setImageDims] = useState({ w: 0, h: 0 });
  // We’ll pass these from <AnnotationCanvas> in onImageLoaded, for instance.
  // (Look at the snippet near the bottom.)

  // This function creates the background polygon = full image minus union of existing annotations.
  const fillBackground = (bgLabelName, bgColor) => {
    // If no image dims known, just ignore
    if (imageDims.w <= 0 || imageDims.h <= 0) {
      alert('Image dimensions unknown. Cannot fill background yet.');
      return;
    }

    // Full image rectangle in "martinez" polygon format
    const fullImagePolygon = [
      [
        [0, 0],
        [imageDims.w, 0],
        [imageDims.w, imageDims.h],
        [0, imageDims.h],
        [0, 0],
      ],
    ];

    // Collect all shapes from currentShapes as polygons
    let unionPolygon = null;
    currentShapes.forEach((shape) => {
      const polyRings = annotationToPolygons(shape);
      if (!polyRings || polyRings.length === 0) return;

      if (unionPolygon === null) {
        unionPolygon = polyRings; // first shape
      } else {
        // union with existing
        unionPolygon = polygonClipping.union(unionPolygon, polyRings);
      }
    });

    // If there's no union (meaning no shapes or we skipped them), then
    // the background is just the entire image.
    let backgroundPolygons = unionPolygon
      ? polygonClipping.diff(fullImagePolygon, unionPolygon)
      : fullImagePolygon;

    if (!backgroundPolygons || backgroundPolygons.length === 0) {
      alert('No empty space found or shapes cover entire image!');
      return;
    }

    // backgroundPolygons is an array of polygons, each polygon is:
    //   [ [ x0, y0 ], [x1, y1], ... [x0, y0] ]
    // but there can be multiple “exterior rings” or holes. 
    // We can create one “background annotation” for each resulting region, or
    // unify them into a single annotation that has multiple rings. 
    // For this code, we’ll create multiple polygons (one annotation per ring):
    // If you'd prefer to have a single multi-ring shape, you'd store it differently.
    // We'll just flatten all polygons into separate annotations.

    const newBackgroundAnnotations = [];

    backgroundPolygons.forEach((polyItem) => {
      // A polygon can itself have multiple rings: [outerRing, hole1, hole2, ...]
      // The library returns an array of such ring arrays.
      // polyItem = [ ring0, ring1 (hole), ring2 (hole), ... ]
      polyItem.forEach((ring) => {
        // ring is an array of [x, y], e.g. [ [0,0], [100,0], [100,100], [0,100], [0,0] ]
        const pointsForAnno = ring.slice(0, -1).map(([px, py]) => ({ x: px, y: py }));
        // (slice(0, -1) to drop the repeated last point if the library duplicates the first).
        // Make a polygon annotation:
        newBackgroundAnnotations.push({
          type: 'polygon',
          points: pointsForAnno,
          label: bgLabelName,
          color: bgColor,
        });
      });
    });

    // Add them to the current shapes
    const updated = [...currentShapes, ...newBackgroundAnnotations];
    handleAnnotationsChange(updated);
  };

  /**
   * Exposed button handler that:
   * 1) chooses a color
   * 2) optionally asks user for a label name or uses “background”
   * 3) calls fillBackground
   */
  const handleFillBackground = () => {
    const color = getBackgroundColor();
    const userLabelName = window.prompt(
      'Enter background label name:',
      'background'
    );
    const labelName = userLabelName?.trim() || 'background';
    fillBackground(labelName, color);
  };

  /////////////////////////////////////////////////////////////////////////
  //                END OF NEW CODE – ONLY ADDED LINES                   //
  /////////////////////////////////////////////////////////////////////////

  return (
    <div className="annotate-container">
      <AnnotationTopBar
        onHome={() => navigate('/')}
        onPrev={handlePrev}
        onNext={handleNext}
        onSave={handleSave}
        onZoomIn={handleZoomIn}
        onZoomOut={handleZoomOut}
        onExport={openExport}
        currentIndex={currentIndex}
        total={files.length}
        taskName={taskName}
      />

      <div style={{ padding: '8px', background: '#eee' }}>
        <button onClick={undo} style={{ marginRight: '8px' }}>
          Undo (Ctrl+Z)
        </button>
        <button onClick={redo} style={{ marginRight: '8px' }}>
          Redo (Ctrl+Y)
        </button>
      </div>

      <div className="annotate-main">
        {/* Tools Sidebar */}
        <div className="tools-sidebar">
          <h3>Tools</h3>
          <label>
            <input
              type="radio"
              name="tool"
              value="move"
              checked={selectedTool === 'move'}
              onChange={() => setSelectedTool('move')}
            />
            <span className="tool-icon">👆</span> Move (M)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="bbox"
              checked={selectedTool === 'bbox'}
              onChange={() => setSelectedTool('bbox')}
            />
            <span className="tool-icon">⬛</span> BBox (B)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polygon"
              checked={selectedTool === 'polygon'}
              onChange={() => setSelectedTool('polygon')}
            />
            <span className="tool-icon">🔺</span> Polygon (P)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polyline"
              checked={selectedTool === 'polyline'}
              onChange={() => setSelectedTool('polyline')}
            />
            <span className="tool-icon">📈</span> Polyline (L)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="point"
              checked={selectedTool === 'point'}
              onChange={() => setSelectedTool('point')}
            />
            <span className="tool-icon">📍</span> Point (O)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="ellipse"
              checked={selectedTool === 'ellipse'}
              onChange={() => setSelectedTool('ellipse')}
            />
            <span className="tool-icon">⬭</span> Ellipse (E)
          </label>

          {/* Segmentation */}
          <label>
            <input
              type="radio"
              name="tool"
              value="segmentation"
              checked={selectedTool === 'segmentation'}
              onChange={() => setSelectedTool('segmentation')}
            />
            <span className="tool-icon">🎨</span> Segmentation (S)
          </label>
          {selectedTool === 'segmentation' && (
            <div style={{ marginLeft: '20px', marginBottom: '8px' }}>
              <label style={{ display: 'block', marginBottom: '4px' }}>
                Type:
              </label>
              <select
                value={segmentationType}
                onChange={(e) => setSegmentationType(e.target.value)}
              >
                <option value="instance">Instance</option>
                <option value="semantic">Semantic</option>
                <option value="panoptic">Panoptic</option>
              </select>

              {/* 
                2) NEW BUTTON: only show this if segType is semantic or panoptic 
                   and only if you want it active in those modes
              */}
              {(segmentationType === 'semantic' ||
                segmentationType === 'panoptic') && (
                  <button
                    onClick={handleFillBackground}
                    style={{
                      marginTop: '8px',
                      background: '#000',
                      color: '#fff',
                      padding: '4px 8px',
                    }}
                  >
                    Fill Background
                  </button>
                )}
            </div>
          )}

          <h3 style={{ marginTop: 16 }}>Active Label</h3>
          <select
            value={selectedLabelClass}
            onChange={(e) => setSelectedLabelClass(e.target.value)}
          >
            {labelClasses.map((lc, i) => (
              <option key={i} value={lc.name}>
                {lc.name}
              </option>
            ))}
          </select>

          <div className="note-area">
            <p>
              <strong>Shortcuts:</strong>
            </p>
            <ul>
              <li>M/B/P/L/O/E => Tools</li>
              <li>S => Segmentation</li>
              <li>Ctrl+S => Save</li>
              <li>Esc => Cancel shape</li>
              <li>ArrowLeft => Prev image</li>
              <li>ArrowRight => Next image</li>
              <li>Ctrl+Z => Undo</li>
              <li>Ctrl+Y => Redo</li>
              <li>Ctrl+C => Copy selected</li>
              <li>Ctrl+V => Paste annotation</li>
            </ul>
          </div>
        </div>

        {/* Canvas */}
        <div className="canvas-area">
          {currentFileUrl ? (
            <AnnotationCanvas
              fileUrl={currentFileUrl}
              annotations={currentShapes}
              onAnnotationsChange={handleAnnotationsChange}
              selectedTool={selectedTool}
              scale={scale}
              onWheelZoom={handleWheelZoom}
              activeLabelColor={
                labelClasses.find((l) => l.name === selectedLabelClass)?.color ||
                '#ff0000'
              }
              onFinishShape={handleFinishShape}
              onDeleteAnnotation={handleDeleteAnnotation}
              activeLabel={selectedLabelClass}
              labelClasses={labelClasses}
              // Pass segmentationType to the canvas
              segmentationType={segmentationType}

              // 3) PASS DOWN A CALLBACK SO THAT CANVAS CAN TELL US IMAGE DIMS
              onImageLoaded={(w, h) => setImageDims({ w, h })}
            />
          ) : (
            <div style={{ textAlign: 'center', margin: 'auto' }}>
              No images found
            </div>
          )}
        </div>

        <AnnotationListSidebar
          annotations={currentShapes}
          onDeleteAnnotation={handleDeleteAnnotation}
          onUpdateAnnotation={handleUpdateAnnotation}
          labelClasses={labelClasses}
        />
      </div>

      {exportOpen && (
        <div className="export-modal-backdrop">
          <div className="export-modal">
            <h2>Export Annotations</h2>
            <p>Select format:</p>
            <div className="export-buttons">
              <button onClick={() => exportAnnotations('coco')}>COCO</button>
              <button onClick={() => exportAnnotations('yolo')}>YOLO</button>
              <button onClick={() => exportAnnotations('pascal')}>
                Pascal VOC
              </button>
            </div>
            <button className="close-btn" onClick={closeExport}>
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
